import React, { useState } from 'react';
import jwtDecode from 'jwt-decode';

const clientId = 'your-client-id';
const redirectUri = window.location.origin + '/callback';
const authorizationEndpoint = 'https://your-authorization-endpoint.com/auth';
const tokenEndpoint = 'https://your-token-endpoint.com/token';
const userInfoEndpoint = 'https://your-userinfo-endpoint.com/userinfo';

function App() {
  const [user, setUser] = useState(null);

  const login = () => {
    const authUrl = `${authorizationEndpoint}?response_type=code&client_id=${clientId}&redirect_uri=${encodeURIComponent(redirectUri)}`;
    window.location.href = authUrl;
  };

  const handleCallback = async (code) => {
    const tokenResponse = await fetch(tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      body: `grant_type=authorization_code&client_id=${clientId}&redirect_uri=${encodeURIComponent(redirectUri)}&code=${code}`
    });

    const tokenData = await tokenResponse.json();
    const idToken = tokenData.id_token;
    const decodedIdToken = jwtDecode(idToken);

    setUser(decodedIdToken);
  };

  React.useEffect(() => {
    if (window.location.search.startsWith('?code=')) {
      const code = window.location.search.substring(5);
      handleCallback(code);
    }
  }, []);

  return (
    <div>
      {user ? (
        <div>
          <h1>Welcome, {user.name}!</h1>
          <p>Email: {user.email}</p>
        </div>
      ) : (
        <button onClick={login}>Login</button>
      )}
    </div>
  );
}

export default App;